**Class structure:**

```ts
export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4; // reasonable limit for a pixel art API

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // aspectRatio is not supported by this fictional API
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size option instead.',
      });
    }

    // seed is not supported
    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      ...(size != null && { size }),
      ...(pixelartOptions?.style != null && { style: pixelartOptions.style }),
      ...(pixelartOptions?.pixelDensity != null && {
        pixel_density: pixelartOptions.pixelDensity,
      }),
    };

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(image => image.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}
```

**Response and error schemas** (at bottom of file, following BFL's pattern at lines 410-458):

```ts
const pixelartImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
  created: z.number(),
});

const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string().optional(),
    type: z.string().optional(),
    code: z.string().optional(),
  }).optional(),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => {
    if (
      typeof error === 'object' &&
      error != null &&
      'error' in error &&
      typeof (error as any).error?.message === 'string'
    ) {
      return (error as any).error.message;
    }
    return 'Unknown PixelArt error';
  },
});
```

Key design decisions for this file:
1. **No polling** - single `postJsonToApi` call, like xAI but even simpler (always b64_json, never URL fallback).
2. **Returns `string[]`** (base64 strings) rather than `Uint8Array[]`. The `ImageModelV3` interface accepts either `Array<string> | Array<Uint8Array>`. Returning strings (base64) directly avoids unnecessary decoding, matching the xAI pattern at line 151.
3. **The `n` parameter** is passed directly to the API (unlike BFL which only supports 1 image per call).
4. **`size`** is passed directly as a string from the standard `ImageModelV3CallOptions.size` field to the API body (the fictional API accepts it).
5. **Provider options** (`style`, `pixelDensity`) are accessed via `providerOptions.pixelart` using `parseProviderOptions`.
6. **`_internal.currentDate`** for testability, matching BFL pattern.

